#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Generator for jxx java8 tz+formatter+gtest pack.

Usage:
  python generate_jxx_java8_tz_formatter_gtest_pack.py --out ./pack --zip

Env vars at runtime (Windows):
  JXX_TIME_ZONE_INFO=...\zoneinfo (must contain localtime)

This script writes C++ sources and tests to the output directory.
"""

import argparse, base64, zipfile
from pathlib import Path

FILES_B64 = {
    'jxx/util/tz/tzif.h': '',
    'jxx/util/tz/tzif.cpp': '',
    'jxx/util/TimeZone.h': '',
    'jxx/util/TimeZone.cpp': '',
    'jxx/util/Date.h': '',
    'jxx/util/Date.cpp': '',
    'jxx/util/Calendar.h': '',
    'jxx/util/Calendar.cpp': '',
    'jxx/util/format/IllegalFormatException.h': '',
    'jxx/util/format/MissingFormatArgumentException.h': '',
    'jxx/util/format/UnknownFormatConversionException.h': '',
    'jxx/util/Formatter.h': '',
    'jxx/util/Formatter.cpp': '',
    'tests/test_timezone.cpp': '',
    'tests/test_formatter_datetime.cpp': '',
    'tests/CMakeLists.txt': '',
    'README.txt': '',
}


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--out', default='jxx_java8_tz_pack', help='output directory')
    ap.add_argument('--zip', action='store_true', help='also create zip next to folder')
    args = ap.parse_args()

    out = Path(args.out).resolve()
    out.mkdir(parents=True, exist_ok=True)

    for rel, b64 in FILES_B64.items():
        p = out / rel
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))

    if args.zip:
        zip_path = out.with_suffix('.zip')
        with zipfile.ZipFile(zip_path, 'w', compression=zipfile.ZIP_DEFLATED) as z:
            for p in out.rglob('*'):
                if p.is_file():
                    z.write(p, arcname=str(p.relative_to(out.parent)))
        print('Wrote zip:', zip_path)

    print('Wrote files to:', out)

if __name__ == '__main__':
    main()
